import threading

class Database:
    def __init__(self):
        self.conn = None # Mock conn

    def save_transaction(self, u1, u2, amount):
        # Bug: No locking for concurrent updates
        u1.balance -= amount
        u2.balance += amount
        self.update_db(u1, u2)

